import{_ as a,a as s}from"./chunks/频繁报错提示.B4wBXruJ.js";import{_ as t,o as i,c as r,a2 as o}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Límites de frecuencia de usuarios","description":"","frontmatter":{},"headers":[],"relativePath":"es/Safety/user-rate-limits.md","filePath":"es/Safety/user-rate-limits.md","lastUpdated":1781962217000}'),n={name:"es/Safety/user-rate-limits.md"};function d(l,e,u,c,p,m){return i(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="limites-de-frecuencia-de-usuarios" tabindex="-1">Límites de frecuencia de usuarios <a class="header-anchor" href="#limites-de-frecuencia-de-usuarios" aria-label="Permalink to &quot;Límites de frecuencia de usuarios&quot;">​</a></h1><p>Los límites de frecuencia controlan el uso cuando una IP o usuario realiza demasiadas acciones en poco tiempo.</p><p>En sitios con subida pública, esta función ayuda a reducir spam, abuso o subidas masivas no deseadas.</p><h2 id="donde-se-configura" tabindex="-1">Dónde se configura <a class="header-anchor" href="#donde-se-configura" aria-label="Permalink to &quot;Dónde se configura&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Configuración del sistema -&gt; Seguridad -&gt; Límites de frecuencia</span></span></code></pre></div><p><img src="'+a+`" alt="Límites de frecuencia" loading="lazy"></p><h2 id="ajustes-principales" tabindex="-1">Ajustes principales <a class="header-anchor" href="#ajustes-principales" aria-label="Permalink to &quot;Ajustes principales&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Ajuste</th><th>Descripción</th></tr></thead><tbody><tr><td>Habilitar</td><td>Activa o desactiva el límite</td></tr><tr><td>Ventana de tiempo</td><td>Periodo usado para contar acciones</td></tr><tr><td>Límite de acciones</td><td>Número máximo permitido dentro de la ventana</td></tr><tr><td>Acción objetivo</td><td>Subida u otra operación que quieras limitar</td></tr><tr><td>Tiempo de bloqueo</td><td>Duración del bloqueo tras superar el límite</td></tr></tbody></table><h2 id="ejemplo-razonable" tabindex="-1">Ejemplo razonable <a class="header-anchor" href="#ejemplo-razonable" aria-label="Permalink to &quot;Ejemplo razonable&quot;">​</a></h2><p>Para una subida pública, empieza con una configuración moderada y ajusta según el uso real.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>30 acciones cada 10 minutos</span></span>
<span class="line"><span>bloqueo de 30 minutos al superar el límite</span></span></code></pre></div><p>Esto suele dejar trabajar a usuarios normales y frena patrones claramente anómalos.</p><h2 id="mensaje-de-error" tabindex="-1">Mensaje de error <a class="header-anchor" href="#mensaje-de-error" aria-label="Permalink to &quot;Mensaje de error&quot;">​</a></h2><p>Cuando se supera el límite, el usuario verá un aviso de que la acción fue rechazada.</p><p><img src="`+s+'" alt="Aviso de errores frecuentes" loading="lazy"></p><h2 id="consejos" tabindex="-1">Consejos <a class="header-anchor" href="#consejos" aria-label="Permalink to &quot;Consejos&quot;">​</a></h2><ul><li>Si el límite es demasiado estricto, puede bloquear subidas legítimas por lotes.</li><li>En sitios públicos, evita dejar la subida totalmente sin límite.</li><li>Combínalo con geolocalización IP y gestión de usuarios para investigar abuso.</li><li>Si esperas un pico temporal de uso, puedes relajar el límite durante ese periodo.</li></ul>',17)])])}const g=t(n,[["render",d]]);export{f as __pageData,g as default};
